sealed class SshAuth {
    
    data class Password(
        val `password`: kotlin.String) : SshAuth()
        
    {
        

        companion object
    }
    
    data class PublicKey(
        val `privateKeyPem`: kotlin.ByteArray) : SshAuth()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeSshAuth : FfiConverterRustBuffer<SshAuth>{
    override fun read(buf: ByteBuffer): SshAuth {
        return when(buf.getInt()) {
            1 -> SshAuth.Password(
                FfiConverterString.read(buf),
                )
            2 -> SshAuth.PublicKey(
                FfiConverterByteArray.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: SshAuth) = when(value) {
        is SshAuth.Password -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`password`)
            )
        }
        is SshAuth.PublicKey -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterByteArray.allocationSize(value.`privateKeyPem`)
            )
        }
    }

    override fun write(value: SshAuth, buf: ByteBuffer) {
        when(value) {
            is SshAuth.Password -> {
                buf.putInt(1)
                FfiConverterString.write(value.`password`, buf)
                Unit
            }
            is SshAuth.PublicKey -> {
                buf.putInt(2)
                FfiConverterByteArray.write(value.`privateKeyPem`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}







sealed class SshException: kotlin.Exception() {
    
    class ConnectionFailed(
        ) : SshException() {
        override val message
            get() = ""
    }
    
    class AuthFailed(
        ) : SshException() {
        override val message
            get() = ""
    }
    
    class HostKeyRejected(
        ) : SshException() {
        override val message
            get() = ""
    }
    
    class IoException(
        ) : SshException() {
        override val message
            get() = ""
    }
    
    class Disconnected(
        ) : SshException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<SshException> {
        override fun lift(error_buf: RustBuffer.ByValue): SshException = FfiConverterTypeSshError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeSshError : FfiConverterRustBuffer<SshException> {
    override fun read(buf: ByteBuffer): SshException {
        

        return when(buf.getInt()) {
            1 -> SshException.ConnectionFailed()
            2 -> SshException.AuthFailed()
            3 -> SshException.HostKeyRejected()
            4 -> SshException.IoException()
            5 -> SshException.Disconnected()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: SshException): ULong {
        return when(value) {
            is SshException.ConnectionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SshException.AuthFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SshException.HostKeyRejected -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SshException.IoException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is SshException.Disconnected -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: SshException, buf: ByteBuffer) {
        when(value) {
            is SshException.ConnectionFailed -> {
                buf.putInt(1)
                Unit
            }
            is SshException.AuthFailed -> {
                buf.putInt(2)
                Unit
            }
            is SshException.HostKeyRejected -> {
                buf.putInt(3)
                Unit
            }
            is SshException.IoException -> {
                buf.putInt(4)
                Unit
            }
            is SshException.Disconnected -> {
                buf.putInt(5)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





public interface SessionCallback {
    
    fun `onData`(`data`: kotlin.ByteArray)
    
    fun `onHostKey`(`fingerprint`: kotlin.String): kotlin.Boolean
    
    fun `onConnected`()
    
    fun `onDisconnected`(`reason`: kotlin.String?)
    
    fun `onScreenUpdate`(`update`: ScreenUpdate)
    
    fun `onTrzszRequest`(`transferId`: kotlin.String, `mode`: kotlin.String, `suggestedName`: kotlin.String?, `expectedSize`: kotlin.ULong?)
    
    fun `onTrzszDownloadChunk`(`transferId`: kotlin.String, `data`: kotlin.ByteArray, `isLast`: kotlin.Boolean)
    
    fun `onTrzszProgress`(`transferId`: kotlin.String, `transferred`: kotlin.ULong, `total`: kotlin.ULong?)
    
    fun `onTrzszFinished`(`transferId`: kotlin.String, `success`: kotlin.Boolean, `message`: kotlin.String?)
    
    companion object
