        }
    }

    override fun allocationSize(value: List<CellData>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterTypeCellData.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
